import { beforeEach, describe, expect, it, vi } from "vitest";
const mockReadActiveStudioSession = vi.fn().mockReturnValue(null);
const mockWriteActiveStudioSession = vi.fn();
const mockNavigateStudioAndAwaitAck = vi.fn().mockResolvedValue({ acked: true });
const mockFetchStreamTip = vi.fn().mockResolvedValue("tip-1");
const mockPollAgentSessionEvents = vi
    .fn()
    .mockReturnValue(new Promise(() => { }));
const mockCreateStudioSession = vi.fn().mockResolvedValue({
    sessionId: "new-session",
    serviceUrl: "https://test.invalid",
});
vi.mock("./activeStudioSession.js", () => ({
    readActiveStudioSession: (...args) => mockReadActiveStudioSession(...args),
    writeActiveStudioSession: (...args) => mockWriteActiveStudioSession(...args),
}));
vi.mock("./agentSessionChannel.js", () => ({
    fetchStreamTip: (...args) => mockFetchStreamTip(...args),
    navigateStudioAndAwaitAck: (...args) => mockNavigateStudioAndAwaitAck(...args),
    pollAgentSessionEvents: (...args) => mockPollAgentSessionEvents(...args),
}));
vi.mock("./commands/createStudioSession.js", () => ({
    createStudioSession: (...args) => mockCreateStudioSession(...args),
}));
vi.mock("./browser.js", () => ({
    openChromelessWindow: vi.fn().mockReturnValue(null),
}));
vi.mock("./agentSessionKey.js", () => ({
    resolveAgentSessionKey: vi.fn().mockReturnValue("test-key"),
}));
vi.mock("./daemon/index.js", () => ({
    DaemonClient: vi.fn(),
    resolveAgentSessionKey: vi.fn().mockReturnValue("test-key"),
}));
import { StudioNavigationError } from "./errors.js";
import { DirectChannel, resolveChannel } from "./studioChannel.js";
beforeEach(() => {
    vi.clearAllMocks();
});
describe("DirectChannel", () => {
    it("creates a new session when no active session exists", async () => {
        const channel = new DirectChannel("key-1", "https://test.invalid");
        const result = await channel.openOrNavigate("/studio");
        expect(result.opened).toBe(true);
        expect(result.sessionId).toBe("new-session");
        expect(mockCreateStudioSession).toHaveBeenCalledWith(expect.objectContaining({
            serviceUrl: "https://test.invalid",
            apiKey: "key-1",
            initialPath: "/studio",
        }));
    });
    it("navigates an existing session when one is recorded", async () => {
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "existing-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
        });
        const channel = new DirectChannel("key-1", "https://test.invalid");
        const result = await channel.openOrNavigate("/studio/traces");
        expect(result.opened).toBe(false);
        expect(result.sessionId).toBe("existing-session");
        expect(mockNavigateStudioAndAwaitAck).toHaveBeenCalledWith(expect.objectContaining({ sessionId: "existing-session" }), "/studio/traces");
        expect(mockCreateStudioSession).not.toHaveBeenCalled();
    });
    it("throws StudioNavigationError when navigation is not acked", async () => {
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "existing-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
        });
        mockNavigateStudioAndAwaitAck.mockResolvedValueOnce({
            acked: false,
            reason: "timeout",
        });
        const channel = new DirectChannel("key-1", "https://test.invalid");
        await expect(channel.openOrNavigate("/studio")).rejects.toThrow(StudioNavigationError);
    });
    it("passes staleSessionId in navigation error", async () => {
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "stale-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
        });
        mockNavigateStudioAndAwaitAck.mockResolvedValueOnce({
            acked: false,
            reason: "timeout",
        });
        const channel = new DirectChannel("key-1", "https://test.invalid");
        try {
            await channel.openOrNavigate("/studio");
        }
        catch (err) {
            expect(err).toBeInstanceOf(StudioNavigationError);
            expect(err.staleSessionId).toBe("stale-session");
        }
    });
    it("subscribe calls fetchStreamTip before polling", async () => {
        const channel = new DirectChannel("key-1", "https://test.invalid");
        const onEvent = vi.fn();
        const onError = vi.fn();
        const sub = channel.subscribe("session-1", onEvent, onError);
        for (let i = 0; i < 20; i++) {
            if (mockPollAgentSessionEvents.mock.calls.length > 0) {
                break;
            }
            await Promise.resolve();
        }
        expect(mockFetchStreamTip).toHaveBeenCalledWith(expect.objectContaining({ sessionId: "session-1" }));
        expect(mockPollAgentSessionEvents).toHaveBeenCalledWith(expect.objectContaining({
            sessionId: "session-1",
            startCursor: "tip-1",
        }));
        sub.abort();
    });
    it("reuses the window when windowState is not closed", async () => {
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "existing-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
            windowState: "open",
        });
        const channel = new DirectChannel("key-1", "https://test.invalid");
        const result = await channel.openOrNavigate("/studio/traces");
        expect(result.opened).toBe(false);
        expect(result.sessionId).toBe("existing-session");
        expect(mockCreateStudioSession).not.toHaveBeenCalled();
    });
    it("creates a new session when windowState is closed", async () => {
        mockReadActiveStudioSession.mockReturnValueOnce({
            sessionId: "closed-session",
            serviceUrl: "https://test.invalid",
            pid: 123,
            startedAt: "2026-01-01T00:00:00.000Z",
            windowState: "closed",
        });
        const channel = new DirectChannel("key-1", "https://test.invalid");
        const result = await channel.openOrNavigate("/studio");
        expect(result.opened).toBe(true);
        expect(result.sessionId).toBe("new-session");
        expect(mockCreateStudioSession).toHaveBeenCalled();
        expect(mockNavigateStudioAndAwaitAck).not.toHaveBeenCalled();
    });
    it("forwards clientHeaders to createStudioSession", async () => {
        const channel = new DirectChannel("key-1", "https://test.invalid");
        await channel.openOrNavigate("/studio", {
            clientHeaders: { "x-custom": "value" },
        });
        expect(mockCreateStudioSession).toHaveBeenCalledWith(expect.objectContaining({
            clientHeaders: { "x-custom": "value" },
        }));
    });
});
describe("resolveChannel", () => {
    it("returns DirectChannel when daemon is not enabled", async () => {
        const channel = await resolveChannel("key-1", "https://test.invalid");
        expect(channel).toBeInstanceOf(DirectChannel);
    });
});
describe("withDirectFallback (via resolveChannel)", () => {
    it("falls back to DirectChannel when daemon openOrNavigate fails", async () => {
        const { DaemonClient } = await import("./daemon/index.js");
        const mockClient = {
            connect: vi.fn().mockResolvedValue(undefined),
            open: vi.fn().mockRejectedValue(new Error("socket dead")),
            destroy: vi.fn(),
            detach: vi.fn().mockResolvedValue(undefined),
            onEvent: vi.fn(),
        };
        // biome-ignore lint/complexity/useArrowFunction: must be a function expression so `new DaemonClient()` works
        vi.mocked(DaemonClient).mockImplementation(function () {
            return mockClient;
        });
        vi.stubEnv("BITFAB_STUDIO_DAEMON", "1");
        const channel = await resolveChannel("key-1", "https://test.invalid");
        const result = await channel.openOrNavigate("/studio");
        expect(result.opened).toBe(true);
        expect(result.sessionId).toBe("new-session");
        expect(mockCreateStudioSession).toHaveBeenCalled();
        vi.unstubAllEnvs();
    });
    it("does not fall back on StudioNavigationError", async () => {
        const { DaemonClient } = await import("./daemon/index.js");
        const mockClient = {
            connect: vi.fn().mockResolvedValue(undefined),
            open: vi.fn().mockResolvedValue({
                ok: true,
                sessionId: "s1",
                browserConnected: true,
                reconnected: true,
            }),
            navigate: vi.fn().mockResolvedValue({ acked: false, reason: "blocked" }),
            destroy: vi.fn(),
            detach: vi.fn().mockResolvedValue(undefined),
            onEvent: vi.fn(),
        };
        // biome-ignore lint/complexity/useArrowFunction: must be a function expression so `new DaemonClient()` works
        vi.mocked(DaemonClient).mockImplementation(function () {
            return mockClient;
        });
        vi.stubEnv("BITFAB_STUDIO_DAEMON", "1");
        const channel = await resolveChannel("key-1", "https://test.invalid");
        await expect(channel.openOrNavigate("/studio")).rejects.toThrow(StudioNavigationError);
        expect(mockCreateStudioSession).not.toHaveBeenCalled();
        vi.unstubAllEnvs();
    });
});
